// Validate required fields from ATS payload
const required = ['full_name', 'email', 'job_title', 'department', 'start_date', 'manager_name', 'location', 'employment_type'];
const item = items[0].json;
const missing = required.filter(f => !item[f]);

return [{
  json: {
    ...item,
    onboarding_id: 'OB-' + Date.now(),
    status: 'INITIATED',
    missing_fields: missing,
    has_missing: missing.length > 0,
    created_at: new Date().toISOString()
  }
}];

