parameters.functionCode:
// Day-1 readiness checklist
const hire = items[0].json;
const startDate = new Date(hire.start_date);
const now = new Date();
const hoursUntilStart = (startDate - now) / (1000 * 60 * 60);

if (hoursUntilStart > 24) return []; // Not yet within 24hr window

const checks = {
  docs_verified: hire.status_docs === 'VERIFIED',
  it_ready: hire.status_it === 'COMPLETE',
  plan_shared: !!hire.onboarding_plan_url,
  manager_notified: hire.manager_notified === true
};

const blockers = Object.entries(checks)
  .filter(([k, v]) => !v)
  .map(([k]) => k);

return [{
  json: {
    ...hire,
    readiness_checks: checks,
    blockers: blockers,
    is_ready: blockers.length === 0
  }
}];

